head.script:
scwin.argObject = null;
scwin.cvNNew = false;
scwin.cvUpdate = false;
scwin.cvDelete = false;
scwin.saveSuccess = false;
scwin.onRollBack = false;
scwin.userId = "";
scwin.cvFixWrkStsCd = "";
scwin.cvTabIndex = 0;
scwin.repFixWrkPlCd = "";
scwin.txt_vehclShortCd = "";
scwin.txt_taxNo = "";
scwin.txt_slipNo = "";
scwin.txt_fileSiz = "";
scwin.txt_fileSavePath = "";

scwin.onpageload = function() {
    scwin.userId = $c.ses.getUserId();
    scwin.argObject = $c.data.getParameter();
    if (scwin.argObject == null) {
        scwin.argObject = {};
    }

    dma_login_query_condition.set("fixEmpNo", scwin.userId);

    scwin.f_OnLoad();
};

scwin.f_OnLoad = async function() {
    await $c.sbm.execute(sbm_login);

    $c.gus.cfDisableObjects([txt_fixWrkPlNm, ica_rglintChkExpireDt, txt_eqClssNm, txt_eqKndNm, txt_eqModelNm, ica_rglintInspExpireDt, txt_acctDeptNm, txt_assgnLobranNm, txt_damageWrongTyp, txt_taxNo, txt_slipNo, em_wrkPlanDt, em_adptWages, ica_mntnInspExpireDt, em_partAmt, em_wages, em_totAmt, em_vatAmt]);

    $c.gus.cfSetIMEModeActiveObjects([txt_vehclNo]);

    if (scwin.argObject.fixWrkNo != null && scwin.argObject.fixWrkNo != "") {
        em_fixWrkPlCd.setValue(scwin.argObject.fixWrkPlCd);
        em_fixWrkNo.setValue(scwin.argObject.fixWrkNo);

        await scwin.f_Retrieve();

        scwin.f_ctrlGrdEnable(false);
        scwin.f_ctrlApplyFixWorkStandardBtn(true);
        scwin.f_ctrlGrdBtn(true);
        scwin.f_ioNesYn();
        scwin.f_setAdjustment();
    } else {
        scwin.cvNNew = true;

        sbm_retrieve.action = "/ps.eq.fixwrkmgnt.fixwrkmgnt.RetrieveFixWorkCMD.do";
        await $c.sbm.execute(sbm_retrieve);

        ds_fix_work.set("homeClsCd", scwin.argObject.homeClsCd || "");
        ds_fix_work.set("travelDtc", "0");
        ds_fix_work.set("applyFixWorkStandardYn", "0");

        em_fixWrkPlCd.setValue(scwin.argObject.fixWrkPlCd || "");
        scwin.f_openCommonPopUp(1, em_fixWrkPlCd.getValue(), '', 'T', 'T');

        em_eqCd.setValue(scwin.argObject.eqCd || "");
        txt_vehclNo.setValue(scwin.argObject.vehclNo || "");

        $c.gus.cfEnableObjects([btn_Edit, btn_SaveTemporary, btn_Save, btn_Del, btn_Close]);

        scwin.f_ctrlApplyFixWorkStandardBtn(false);
        scwin.f_ctrlGrdBtn(false);

        btn_Edit.setDisabled(true);
        btn_Del.setDisabled(true);

        if (scwin.argObject.fixKndCd != null && scwin.argObject.fixKndCd != "") {
            lux_fixKndCd.setValue(scwin.argObject.fixKndCd);
        } else {
            lux_fixKndCd.setSelectedIndex(0);
        }

        if (scwin.argObject.selfOutordClsCd != null && scwin.argObject.selfOutordClsCd != "") {
            lux_selfOutordClsCd.setValue(scwin.argObject.selfOutordClsCd);
        } else {
            lux_selfOutordClsCd.setSelectedIndex(0);
        }

        lux_fixCauseCd.setSelectedIndex(0);
        lux_fixCatCd.setSelectedIndex(0);

        $c.gus.cfDisableObjects([txt_accdRecptNo, em_circulPartCd, txt_circulPartNm, img_accdRecptNo]);

        lux_fixWrkStsCd.setValue("R");

        chk_ioNesYn.setValue("1");
        scwin.f_ioNesYn();

        em_fixWrkPlCd.setFocus();

        if (em_eqCd.getValue() != "" && txt_vehclNo.getValue() != "") {
            scwin.f_openCommonPopUp(2, em_eqCd.getValue(), txt_vehclNo.getValue(), 'T', 'T');
        }
    }

    scwin.f_selfOutordCls();

    ds_fix_work.set("applyFixWorkStandardYn", "0");

    if (!(scwin.argObject.homeClsCd == "TR" && em_fixWrkPlCd.getValue() != "201")) {
        if (ds_login.get("fixEmpClsCd") == "2") {
            btn_Save.setDisabled(true);
        }
    }

    scwin.repFixWrkPlCd = await scwin.f_retrieveRepFixWrkPl();
};

scwin.f_Retrieve = async function() {
    let strAction = "/ps.eq.fixwrkmgnt.fixwrkmgnt.RetrieveFixWorkCMD.do";

    dma_fix_work_re.set("fixWrkPlCd", em_fixWrkPlCd.getValue());
    dma_fix_work_re.set("fixWrkNo", em_fixWrkNo.getValue());

    sbm_retrieve.action = strAction;
    await $c.sbm.execute(sbm_retrieve);

    scwin.cvFixWrkStsCd = ds_fix_work.get("fixWrkStsCd");

    lux_fixWrkStsCd.setValue(ds_fix_work.get("fixWrkStsCd"));

    ds_fix_work.set("applyFixWorkStandardYn", "0");

    $c.gus.cfEnableObjects([btn_Edit, btn_SaveTemporary, btn_Save, btn_Del, btn_Close]);
    $c.gus.cfDisableObjects([btn_Save, btn_SaveTemporary]);

    $c.gus.cfDisableKeyData();

    let wrkStDtVal = ica_wrkStDt.getValue();
    let wrkEndDtVal = ica_wrkEndDt.getValue();
    if (wrkStDtVal != "" && wrkEndDtVal != "") {
        em_needDt.setValue($c.date.diffDate(wrkStDtVal, wrkEndDtVal));
    }
};

scwin.sbm_retrieve_submitdone = function(e) {
    scwin.f_setAdjustment();
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_applyFixWorkStandard_submitdone = function(e) {
};

scwin.sbm_applyFixWorkStandard_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_applyFixWorkUnit_submitdone = function(e) {
};

scwin.sbm_applyFixWorkUnit_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_login_submitdone = function(e) {
};

scwin.sbm_login_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_repFixWrkPl_submitdone = function(e) {
};

scwin.sbm_repFixWrkPl_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_save_submitdone = async function(e) {
    if (scwin.cvDelete == true) {
        await $c.gus.cfAlertMsg(MSG_CM_INF_004);
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    }
    scwin.saveSuccess = true;
};

scwin.sbm_save_submiterror = function(e) {
    scwin.saveSuccess = false;
    $c.gus.cfShowError(e);
};

scwin.btn_Edit_onclick = function(e) {
    scwin.f_Update();
};

scwin.btn_SaveTemporary_onclick = function(e) {
    scwin.f_SaveTemporary();
};

scwin.btn_Save_onclick = function(e) {
    scwin.f_Save();
};

scwin.btn_Del_onclick = function(e) {
    scwin.f_Delete();
};

scwin.btn_Close_onclick = function(e) {
    $c.win.closePopup();
};

scwin.f_Update = async function() {
    let wrkEndDtVal = ica_wrkEndDt.getValue();
    if (wrkEndDtVal != "") {
        if ($c.gus.cfJobCloseYN("CUR", wrkEndDtVal.substring(0, 6), "00", "EQ01", scwin.repFixWrkPlCd, null, "N") == 2) {
            await $c.win.alert(wrkEndDtVal.substring(0, 4) + "년 " + wrkEndDtVal.substring(4, 6) + "월의 마감이 이미 완료되었습니다.");
            return;
        }
    }

    scwin.cvUpdate = true;

    $c.gus.cfEnableKeyData();
    $c.gus.cfDisableKey();

    $c.gus.cfEnableObjects([btn_Edit, btn_SaveTemporary, btn_Save, btn_Del, btn_Close]);
    $c.gus.cfDisableObjects([btn_Edit, em_partAmt, em_wages, em_totAmt, em_vatAmt]);

    scwin.f_selfOutordCls();

    ds_fix_work.set("applyFixWorkStandardYn", "0");

    scwin.f_ctrlFixKndCd();

    scwin.f_ctrlGrdBtn(false);

    if (scwin.cvFixWrkStsCd == "C") {
        $c.gus.cfDisableObjects([btn_SaveTemporary]);
        scwin.f_ctrlApplyFixWorkStandardBtn(true);
        $c.gus.cfDisableObjects([ica_wrkEndDt, em_wrkEndHh]);
    } else if (scwin.cvFixWrkStsCd == "I") {
        scwin.f_ctrlApplyFixWorkStandardBtn(false);
    } else {
        scwin.f_ctrlApplyFixWorkStandardBtn(true);
    }

    scwin.f_ioNesYn();

    $c.gus.cfDisableObjects([em_wrkPlanDt, lux_selfOutordClsCd]);

    scwin.f_ctrlGrdEnable(true);
};

scwin.f_SaveTemporary = async function() {
    if (ds_fix_work_standard.getUpdatedIndex().length == 0 && ds_fix_work_unit.getUpdatedIndex().length == 0 &&
        ds_fix_driver.getUpdatedIndex().length == 0 && ds_repair_circula_parts.getUpdatedIndex().length == 0 &&
        ds_fix_work_parts.getUpdatedIndex().length == 0) {
        let isChanged = false;
        if (ds_fix_work.get("fixWrkNo") != ds_fix_work_no.get("fixWrkNo")) isChanged = true;
        if (!isChanged) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["작업지시 기본정보 및 상세정보"]);
            return;
        }
    }

    if (!(await scwin.f_SaveValid("SaveTemporary"))) return;

    if (lux_selfOutordClsCd.getValue() == "OT") {
        if (scwin.f_vatChk()) {
            return;
        }
    }

    let fixWrkStsCdPre = lux_fixWrkStsCd.getValue();

    lux_fixWrkStsCd.setValue("R");

    scwin.saveSuccess = false;
    await $c.sbm.execute(sbm_save);
    if (scwin.saveSuccess == false) {
        lux_fixWrkStsCd.setValue(fixWrkStsCdPre);
        return;
    }

    $c.gus.cfDisableKeyData();

    $c.gus.cfEnableObjects([btn_Edit, btn_SaveTemporary, btn_Save, btn_Del, btn_Close]);
    $c.gus.cfDisableObjects([btn_Save, btn_SaveTemporary]);

    scwin.f_ctrlApplyFixWorkStandardBtn(true);
    scwin.f_ctrlGrdBtn(true);

    scwin.f_ctrlGrdEnable(false);

    em_fixWrkPlCd.setReadOnly(true);

    await scwin.f_Retrieve();
};

scwin.f_Save = async function() {
    if (!(await scwin.f_SaveValid("Save"))) return;

    if (lux_selfOutordClsCd.getValue() == "OT") {
        if (scwin.f_vatChk()) {
            return;
        }
    }

    let fixKndCdVal = lux_fixKndCd.getValue();
    if (fixKndCdVal == "13" || fixKndCdVal == "14" || fixKndCdVal == "15") {
        if (ds_fix_work.get("fileNm") == "") {
            await $c.win.alert("정기점검, 정기검사, 종합검사시 자동차등록증 첨부는 필수입니다.");
            return;
        }
    }

    for (let row = 0; row < ds_fix_work_parts.getRowCount(); row++) {
        if (ds_fix_work_parts.getRowStatus(row) == "R") {
            ds_fix_work_parts.setRowStatus(row, "C");
        }
    }

    for (let row = 0; row < ds_repair_circula_parts.getRowCount(); row++) {
        if (ds_repair_circula_parts.getRowStatus(row) == "R") {
            ds_repair_circula_parts.setRowStatus(row, "C");
        }
    }

    let fixWrkStsCdPre = lux_fixWrkStsCd.getValue();

    lux_fixWrkStsCd.setValue("C");

    scwin.saveSuccess = false;
    await $c.sbm.execute(sbm_save);
    if (scwin.saveSuccess == false) {
        lux_fixWrkStsCd.setValue(fixWrkStsCdPre);
        return;
    }

    $c.gus.cfDisableKeyData();

    $c.gus.cfEnableObjects([btn_Edit, btn_SaveTemporary, btn_Save, btn_Del, btn_Close]);
    $c.gus.cfDisableObjects([btn_Save, btn_SaveTemporary]);

    scwin.f_ctrlApplyFixWorkStandardBtn(true);
    scwin.f_ctrlGrdBtn(true);

    scwin.f_ctrlGrdEnable(false);

    em_fixWrkPlCd.setReadOnly(true);
    await scwin.f_Retrieve();
    scwin.f_ctrlGrdBtn(true);
    scwin.f_ioNesYn();
    scwin.f_setAdjustment();
};

scwin.f_SaveValid = async function(saveType) {
    $c.gus.cfRefreshMandSign();

    let chk = await $c.gus.cfValidate([tb_work]);
    if (!chk) return false;

    let wrkEndDtVal = ica_wrkEndDt.getValue();
    if (wrkEndDtVal != "") {
        if ($c.gus.cfJobCloseYN("CUR", wrkEndDtVal.substring(0, 6), "00", "EQ01", scwin.repFixWrkPlCd, null, "N") == 2) {
            await $c.win.alert(wrkEndDtVal.substring(0, 4) + "년 " + wrkEndDtVal.substring(4, 6) + "월의 마감이 이미 완료되었습니다.");
            return false;
        }
    }

    let fixKndCdVal = lux_fixKndCd.getValue();
    if (fixKndCdVal == "13" || fixKndCdVal == "14" || fixKndCdVal == "15") {
        let inspAgencyClntNo = em_inspAgencyClntNo.getValue();
        if (inspAgencyClntNo.length == 0) {
            await $c.win.alert("점검/검사인 경우 검사대행업체는 필수입력입니다.");
            return false;
        }
        let inspDtVal = em_inspDt.getValue();
        if (inspDtVal.length > 0 && chk_advcdProcYn.getValue() != "1") {
            if (inspAgencyClntNo.length == 0) {
                await $c.win.alert("점검/검사이고 전도금이 아닌 경우 검사대행업체는 필수입력입니다.");
                return false;
            }
            let inspCost = parseInt(em_inspCost.getValue() || "0") + parseInt(em_agencyCost.getValue() || "0");
            let inspCostVat = parseInt(em_inspCostVat.getValue() || "0");
            if (inspCost > 0 && inspCostVat == 0) {
                await $c.win.alert("점검/검사이고 전도금이 아닌 경우 검사비부가세는 필수입력입니다.");
                return false;
            }
        } else if (inspDtVal.length > 0 && chk_advcdProcYn.getValue() == "1") {
            let inspCost = parseInt(em_inspCost.getValue() || "0") + parseInt(em_agencyCost.getValue() || "0");
            let inspCostVat = parseInt(em_inspCostVat.getValue() || "0");
            if (inspCost > 0 && inspCostVat > 0) {
                await $c.win.alert("점검/검사이고 전도금인 경우 검사비부가세는 입력할 수 없습니다.");
                return false;
            }
        }
    }

    if (saveType == "Save") {
        let chk2 = await $c.gus.cfValidate([tbl_eq]);
        if (!chk2) return false;
        let chk3 = await $c.gus.cfValidate([tb_work_detail]);
        if (!chk3) return false;

        if (ds_fix_work.get("homeClsCd") == "TR") {
            let wrkStDtVal = ica_wrkStDt.getValue().trim();
            let wrkEndDtValTrim = ica_wrkEndDt.getValue().trim();
            if (wrkStDtVal != "" && wrkEndDtValTrim != "") {
                if (wrkStDtVal.substring(0, 6) != wrkEndDtValTrim.substring(0, 6)) {
                    await $c.win.alert("작업시작월과 종료월은 동일 해야 합니다.");
                    return false;
                }
            }
        }

        let wrkStDtVal = ica_wrkStDt.getValue().trim();
        let wrkEndDtValTrim = ica_wrkEndDt.getValue().trim();
        if (wrkStDtVal != "" && wrkEndDtValTrim != "") {
            if ((wrkStDtVal + "" + em_wrkStHh.getValue().trim()) > (wrkEndDtValTrim + "" + em_wrkEndHh.getValue().trim())) {
                await $c.win.alert("작업시작일시는 작업완료일시 이전이어야 합니다.");
                ica_wrkStDt.setFocus();
                return false;
            }
        }

        let inDtVal = ica_inDt.getValue().trim();
        let outDtVal = ica_outDt.getValue().trim();
        if (inDtVal != "" && outDtVal != "") {
            if ((inDtVal + "" + em_inHh.getValue().trim()) > (outDtVal + "" + em_outHh.getValue().trim())) {
                await $c.win.alert("입고일시는 출고일시 이전이어야 합니다.");
                ica_inDt.setFocus();
                return false;
            }
        }

        if (ica_inDt.getMandatory && ica_inDt.getMandatory() == true) {
            if (inDtVal != "" && wrkStDtVal != "") {
                if ((inDtVal + "" + em_inHh.getValue().trim()) > (wrkStDtVal + "" + em_wrkStHh.getValue().trim())) {
                    await $c.win.alert("입고일시는 작업시작일시보다 이전이어야 합니다.");
                    ica_inDt.setFocus();
                    return false;
                }
            }
        }

        if (ica_outDt.getMandatory && ica_outDt.getMandatory() == true) {
            if (outDtVal != "" && wrkEndDtValTrim != "") {
                if ((outDtVal + "" + em_outHh.getValue().trim()) < (wrkEndDtValTrim + "" + em_wrkEndHh.getValue().trim())) {
                    await $c.win.alert("출고일시는 작업완료일시보다 이후이어야 합니다.");
                    ica_outDt.setFocus();
                    return false;
                }
            }
        }

        if (fixKndCdVal == "14" || fixKndCdVal == "15") {
            if (lux_selfOutordClsCd.getValue() == "IN") {
                for (let i = 0; i < ds_fix_work_parts.getRowCount(); i++) {
                    if (ds_fix_work_parts.getRowStatus(i) == "D") continue;
                    if ((ds_fix_work_parts.getCellData(i, "stockQty") < ds_fix_work_parts.getCellData(i, "partQty") || ds_fix_work_parts.getCellData(i, "stockQty") <= 0) && ds_fix_work_parts.getCellData(i, "partOutNo") == "") {
                        await $c.win.alert("부품재고가 없습니다.");
                        return false;
                    }
                }
            } else {
                if (ds_fix_work_unit.getRowCount() < 1) {
                    await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["작업단위 정보"]);
                    return false;
                }
                for (let i = 0; i < ds_fix_work_parts.getRowCount(); i++) {
                    if (ds_fix_work_parts.getRowStatus(i) == "D") continue;
                    if ((ds_fix_work_parts.getCellData(i, "stockQty") < ds_fix_work_parts.getCellData(i, "partQty") || ds_fix_work_parts.getCellData(i, "stockQty") <= 0) && ds_fix_work_parts.getCellData(i, "partOutNo") == "") {
                        await $c.win.alert("부품재고가 없습니다.");
                        return false;
                    }
                }
            }
        } else if (fixKndCdVal == "13") {
            let nextExpireDtVal = ica_nextExpireDt.getValue();
            if (nextExpireDtVal.length > 0) {
                if (nextExpireDtVal.length != 8) {
                    await $c.win.alert("다음검사 예정일은 8자리수만큼 입력하십시오");
                    return false;
                }
            }
            let chkInsp = await $c.gus.cfValidate([em_inspDt, em_agencyCost, em_inspCost]);
            if (!chkInsp) return false;
        } else {
            if (lux_selfOutordClsCd.getValue() == "IN") {
                if (ds_fix_driver.getRowCount() < 1) {
                    await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["정비사 정보"]);
                    return false;
                }
                let chkDriver = await $c.gus.cfValidate([gr_fix_driver]);
                if (!chkDriver) return false;

                for (let i = 0; i < ds_fix_driver.getRowCount(); i++) {
                    if (ds_fix_driver.getCellData(i, "wrkHhCnt") == 0) {
                        await $c.win.alert("정비사의 정비시간은 0보다 커야 합니다.");
                        gr_fix_driver.setFocusedCell(i, "wrkHhCnt");
                        return false;
                    }
                }
            }

            for (let i = 0; i < ds_fix_work_parts.getRowCount(); i++) {
                if (ds_fix_work_parts.getRowStatus(i) == "D") continue;
                if ((ds_fix_work_parts.getCellData(i, "stockQty") < ds_fix_work_parts.getCellData(i, "partQty") || ds_fix_work_parts.getCellData(i, "stockQty") <= 0) && ds_fix_work_parts.getCellData(i, "partOutNo") == "") {
                    await $c.win.alert("부품재고가 없습니다.");
                    return false;
                }
            }
        }
    } else {
        let chk4 = await $c.gus.cfValidate([tbl_eq]);
        if (!chk4) return false;
        let chk5 = await $c.gus.cfValidate([em_wrkIntendDt, em_endIntendDt]);
        if (!chk5) return false;

        let wrkStDtVal = ica_wrkStDt.getValue().trim();
        let wrkEndDtValTrim = ica_wrkEndDt.getValue().trim();
        if (wrkStDtVal != "" && wrkEndDtValTrim != "") {
            if (ds_fix_work.get("homeClsCd") == "TR") {
                if (wrkStDtVal.substring(0, 6) != wrkEndDtValTrim.substring(0, 6)) {
                    await $c.win.alert("작업시작월과 종료월은 동일 해야 합니다.");
                    return false;
                }
            }
            if ((wrkStDtVal + "" + em_wrkStHh.getValue().trim()) > (wrkEndDtValTrim + "" + em_wrkEndHh.getValue().trim())) {
                await $c.win.alert("작업시작일시는 작업완료일시 이전이어야 합니다.");
                ica_wrkStDt.setFocus();
                return false;
            }
        }

        let inDtVal = ica_inDt.getValue().trim();
        let outDtVal = ica_outDt.getValue().trim();
        if (inDtVal != "" && outDtVal != "") {
            if ((inDtVal + "" + em_inHh.getValue().trim()) > (outDtVal + "" + em_outHh.getValue().trim())) {
                await $c.win.alert("입고일시는 출고일시 이전이어야 합니다.");
                ica_inDt.setFocus();
                return false;
            }
        }

        if (fixKndCdVal == "13" || fixKndCdVal == "14" || fixKndCdVal == "15") {
            if (lux_selfOutordClsCd.getValue() == "IN") {
                for (let i = 0; i < ds_fix_driver.getRowCount(); i++) {
                    if (ds_fix_driver.getCellData(i, "wrkHhCnt") == 0) {
                        await $c.win.alert("정비사의 정비시간은 0보다 커야 합니다.");
                        gr_fix_driver.setFocusedCell(i, "wrkHhCnt");
                        return false;
                    }
                }
            }
        } else {
            if (lux_selfOutordClsCd.getValue() == "IN") {
                for (let i = 0; i < ds_fix_driver.getRowCount(); i++) {
                    if (ds_fix_driver.getCellData(i, "wrkHhCnt") == 0) {
                        await $c.win.alert("정비사의 정비시간은 0보다 커야 합니다.");
                        gr_fix_driver.setFocusedCell(i, "wrkHhCnt");
                        return false;
                    }
                }
            }
        }
    }

    if (scwin.argObject.homeClsCd == "LO") {
        if (ds_fix_work.get("totTimeYn") == "Y") {
            let totOprtVal = em_totOprtHhCnt.getValue();
            if (totOprtVal <= 0 || totOprtVal == null || totOprtVal == "") {
                await $c.win.alert("총가동 시간을 입력해 주세요.");
                em_totOprtHhCnt.setFocus();
                return false;
            }
        }
    }

    ds_fix_work.set("vehclNo", txt_vehclNo.getValue());

    let wrkStDtFinal = ica_wrkStDt.getValue();
    let wrkEndDtFinal = ica_wrkEndDt.getValue();
    if (wrkStDtFinal != "" && wrkEndDtFinal != "") {
        em_needDt.setValue($c.date.diffDate(wrkStDtFinal, wrkEndDtFinal));
    }

    if (scwin.cvUpdate == true) {
        // TODO: ds_fix_work UseChangeInfo equivalent
    }

    if (saveType == "Save") {
        for (let row = 0; row < ds_fix_work_unit.getRowCount(); row++) {
            if (ds_fix_work_unit.getCellData(row, "wrkHhCnt") == "0") {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_013, ["작업단위의 실제정비시간", "0"]);
                return false;
            }
        }
        for (let row = 0; row < ds_fix_work_parts.getRowCount(); row++) {
            if (ds_fix_work_parts.getCellData(row, "partQty") == "0") {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_013, ["소요부품의 사용수량", "0"]);
                return false;
            }
            if (ds_fix_work_parts.getCellData(row, "realOutDt").trim() != "" && wrkEndDtFinal.trim() != "") {
                if (ds_fix_work_parts.getCellData(row, "realOutDt").substr(0, 6) != wrkEndDtFinal.substr(0, 6)) {
                    await $c.win.alert("실 출고일자는 작업완료일자와 같은 월이어야 합니다.");
                    return false;
                }
            }
        }
        sbm_save.action = "/ps.eq.fixwrkmgnt.fixwrkmgnt.RegistFixWorkConsequenceCMD.do";
    } else if (saveType == "SaveTemporary") {
        if (scwin.cvNNew == true) {
            sbm_save.action = "/ps.eq.fixwrkmgnt.fixwrkmgnt.SaveFixWorkConsequenceTemporaryCMD.do";
        }
        if (scwin.cvUpdate == true) {
            sbm_save.action = "/ps.eq.fixwrkmgnt.fixwrkmgnt.UpdateFixWorkConsequenceCMD.do";
        }
    }

    return true;
};

scwin.f_Delete = async function() {
    let wrkEndDtVal = ica_wrkEndDt.getValue();
    if (wrkEndDtVal != "") {
        if ($c.gus.cfJobCloseYN("CUR", wrkEndDtVal.substring(0, 6), "00", "EQ01", scwin.repFixWrkPlCd, null, "N") == 2) {
            await $c.win.alert(wrkEndDtVal.substring(0, 4) + "년 " + wrkEndDtVal.substring(4, 6) + "월의 마감이 이미 완료되었습니다.");
            return;
        }
    }

    let chk = await $c.win.confirm("삭제하시겠습니까?");
    if (chk) {
        scwin.cvDelete = true;

        sbm_save.action = "/ps.eq.fixwrkmgnt.fixwrkmgnt.DeleteFixWorkConsequenceCMD.do";
        await $c.sbm.execute(sbm_save);

        $c.win.closePopup("REFRESH");
    }
};

scwin.f_DeleteMarked = function() {
    let pos = ds_fix_work_unit.getRowPosition();
    if (pos < 0) return;
    let fixWrkUnitNo = ds_fix_work_unit.getCellData(pos, "fixWrkUnitNo");

    for (let row = ds_fix_work_parts.getRowCount() - 1; row >= 0; row--) {
        if (ds_fix_work_parts.getCellData(row, "fixWrkUnitNo") == fixWrkUnitNo) {
            ds_fix_work_parts.removeRow(row);
        }
    }
    for (let row = ds_fix_driver.getRowCount() - 1; row >= 0; row--) {
        if (ds_fix_driver.getCellData(row, "fixWrkUnitNo") == fixWrkUnitNo) {
            ds_fix_driver.removeRow(row);
        }
    }
};

scwin.f_UndoMarked = function() {
    let pos = ds_fix_work_unit.getRowPosition();
    if (pos < 0) return;
    let fixWrkUnitNo = ds_fix_work_unit.getCellData(pos, "fixWrkUnitNo");

    for (let row = 0; row < ds_fix_work_parts.getRowCount(); row++) {
        if (ds_fix_work_parts.getCellData(row, "fixWrkUnitNo") == fixWrkUnitNo) {
            ds_fix_work_parts.undoRow(row);
        }
    }
    for (let row = 0; row < ds_fix_driver.getRowCount(); row++) {
        if (ds_fix_driver.getCellData(row, "fixWrkUnitNo") == fixWrkUnitNo) {
            ds_fix_driver.undoRow(row);
        }
    }
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList;

    switch (disGubun) {
        case 1:
            rtnList = $c.gus.cfCommonPopUp('retrieveWorkPlaceInfo', pCode, pName, pClose, null, null, null, null, scwin.argObject.homeClsCd, null, null, null, null, null, pAllSearch, "작업장조회,작업장코드,작업장명");
            $c.gus.cfSetReturnValue(rtnList, em_fixWrkPlCd, txt_fixWrkPlNm);
            if (rtnList != null && rtnList[0] != "N/A") {
                em_adptWages.setValue(parseInt(rtnList[3]));
            }
            break;

        case 2:
            let argDt = "";
            if (ica_wrkEndDt.getValue().trim() == "") {
                argDt = "XXXX";
            } else {
                argDt = ica_wrkEndDt.getValue().trim();
            }
            rtnList = $c.gus.cfCommonPopUp('retrieveEqBasicListInfo', pCode, pName, pClose, null, null, null, null, scwin.argObject.homeClsCd + ",,," + argDt + "," + argDt, null, null, null, null, null, "F", "장비,장비코드,차량번호");
            if (rtnList != null && rtnList[0] != "N/A") {
                em_eqCd.setValue(rtnList[0]);
                txt_vehclNo.setValue(rtnList[1]);
                scwin.txt_vehclShortCd = rtnList[2];
                ica_rglintInspExpireDt.setValue(rtnList[4]);
                txt_eqClssNm.setValue(rtnList[5]);
                txt_eqKndNm.setValue(rtnList[6]);
                txt_eqModelNm.setValue(rtnList[3]);
                ica_rglintChkExpireDt.setValue(rtnList[7]);
                txt_acctDeptNm.setValue(rtnList[8]);
                txt_assgnLobranNm.setValue(rtnList[9]);

                // TODO: ds_fixEquipment DataID load equivalent
                ica_mntnInspExpireDt.setValue("");

                if (scwin.argObject.homeClsCd == "LO") {
                    scwin.f_openCommonPopUp(7, em_eqCd.getValue(), '', 'T', 'F');
                }
            } else {
                em_eqCd.setValue("");
                txt_vehclNo.setValue("");
                scwin.txt_vehclShortCd = "";
                ica_rglintInspExpireDt.setValue("");
                txt_eqClssNm.setValue("");
                txt_eqKndNm.setValue("");
                txt_eqModelNm.setValue("");
                ica_rglintChkExpireDt.setValue("");
                txt_acctDeptNm.setValue("");
                txt_assgnLobranNm.setValue("");
                ica_mntnInspExpireDt.setValue("");
            }
            break;

        case 3:
            rtnList = $c.gus.cfCommonPopUp('retrieveFixClntList', pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, "F", "외주정비거래처조회,거래처코드,거래처명");
            $c.gus.cfSetReturnValue(rtnList, em_outordFixClntNo, txt_outordFixClntNm);
            break;

        case 4:
            rtnList = $c.gus.cfCommonPopUp('retrievePartYnInfo', pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, "수리순환부품조회,부품코드,부품명");
            $c.gus.cfSetReturnValue(rtnList, em_circulPartCd, txt_circulPartNm);
            break;

        case 5:
            rtnList = $c.gus.cfCommonPopUp('retrieveFixClntList', pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, "F", "검사대행업체,거래처코드,거래처명");
            $c.gus.cfSetReturnValue(rtnList, em_inspAgencyClntNo, txt_inspAgencyClntNm);
            if (rtnList != null && rtnList[0] != "N/A") {
                em_inspCost.setFocus();
            }
            break;

        case 6:
            rtnList = $c.gus.cfCommonPopUp('retrieveAccdNoInfo', pCode, pName, pClose, null, null, null, null, "," + em_eqCd.getValue(), null, null, null, null, null, pAllSearch, null);
            $c.gus.cfSetReturnValue(rtnList, txt_accdRecptNo, null, [txt_damageWrongTyp]);
            break;

        case 7:
            rtnList = $c.gus.cfCommonPopUp('retrieveEqTotTimeInfo', pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, 'T', null);
            if (rtnList != null && rtnList[0] != "N/A") {
                ds_fix_work.set("totTimeYn", rtnList[7]);
            }
            break;

        default:
            break;
    }
};

scwin.f_chkOpenCommonPopUp = function(disGubun, inObj, pairObj, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        if (disGubun == 2) {
            ica_rglintChkExpireDt.setValue("");
            txt_eqClssNm.setValue("");
            txt_eqKndNm.setValue("");
            txt_eqModelNm.setValue("");
            ica_rglintInspExpireDt.setValue("");
            txt_acctDeptNm.setValue("");
            txt_assgnLobranNm.setValue("");
        } else if (disGubun == 1) {
            em_adptWages.setValue("0");
        }
        return;
    }

    $c.gus.cfClearPairObj(pairObj);

    if (disGubun == 2) {
        ica_rglintChkExpireDt.setValue("");
        txt_eqClssNm.setValue("");
        txt_eqKndNm.setValue("");
        txt_eqModelNm.setValue("");
        ica_rglintInspExpireDt.setValue("");
        txt_acctDeptNm.setValue("");
        txt_assgnLobranNm.setValue("");
    }

    let pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.f_openCommPopUpGrid = async function(disGubun, row, pClose) {
    let rtnList;
    let pCode = "";
    let pName = "";
    let sameFixWrkUnitNo = 0;

    switch (disGubun) {
        case 1:
            pCode = ds_fix_work_standard.getCellData(row, "fixWrkStndNo");
            rtnList = $c.gus.cfCommonPopUp('retrieveFixWrkSdListInfo', pCode, pName, pClose, null, null, null, null, scwin.argObject.homeClsCd, null, null, null, null, null, "T", "작업표준정보,작업표준코드,작업표준명");
            $c.gus.cfSetGridReturnValue(rtnList, ds_fix_work_standard, row, "fixWrkStndNo", "wrkStndNm");
            break;

        case 2:
            pCode = ds_fix_work_unit.getCellData(row, "fixWrkUnitNo");
            rtnList = $c.gus.cfCommonPopUp('retrieveFixWrkUnitListInfo', pCode, pName, pClose, null, null, null, null, scwin.argObject.homeClsCd, null, null, null, null, null, "F", "작업단위정보,작업단위코드,작업단위명");
            $c.gus.cfSetGridReturnValue(rtnList, ds_fix_work_unit, row, "fixWrkUnitNo", "fixWrkUnitNm", ["stndWrkHhCnt"]);
            if (rtnList != null && rtnList[0] != "N/A" && rtnList != undefined) {
                scwin.f_applyFixWorkUnit(row, rtnList[0]);
            }
            break;

        case 3:
            pCode = ds_fix_driver.getCellData(row, "fixWrkUnitNo");
            rtnList = $c.gus.cfCommonPopUp('retrieveFixWrkUnitListInfo', pCode, pName, pClose, null, null, null, null, scwin.argObject.homeClsCd, null, null, null, null, null, "F", "작업단위정보,작업단위코드,작업단위명");
            sameFixWrkUnitNo = 0;
            if (rtnList != null && rtnList[0] != "N/A" && rtnList != undefined) {
                for (let i = 0; i < ds_fix_work_unit.getRowCount(); i++) {
                    if (ds_fix_work_unit.getCellData(i, "fixWrkUnitNo") == rtnList[0]) {
                        sameFixWrkUnitNo = 1;
                        break;
                    }
                }
                if (sameFixWrkUnitNo == 0) {
                    ds_fix_driver.setCellData(ds_fix_driver.getRowPosition(), "fixWrkUnitNo", "");
                    await $c.win.alert("작업단위에 등록된 작업단위번호만 입력가능합니다.");
                    return false;
                }
            }
            $c.gus.cfSetGridReturnValue(rtnList, ds_fix_driver, row, "fixWrkUnitNo", "");
            break;

        case 4:
            pName = ds_fix_driver.getCellData(row, "fixEmpNm");
            let addWhere4 = "," + (scwin.argObject.fixWrkPlCd || "") + ",2";
            rtnList = $c.gus.cfCommonPopUp("retrieveFixEmpInfo", pCode, pName, pClose, null, null, null, null, addWhere4, null, null, null, null, null, "T", "정비사정보,정비사코드,정비사명");
            $c.gus.cfSetGridReturnValue(rtnList, ds_fix_driver, row, "fixEmpNo", "fixEmpNm");
            break;

        case 5:
            pCode = ds_repair_circula_parts.getCellData(row, "circulPartCd");
            rtnList = $c.gus.cfCommonPopUp('retrievePartYnInfo', pCode, pName, pClose, null, null, null, null, scwin.argObject.homeClsCd, null, null, null, null, null, "T", "수리순환품정보,부품코드,부품명");
            $c.gus.cfSetGridReturnValue(rtnList, ds_repair_circula_parts, row, "circulPartCd", "circulPartNm");
            break;

        case 6:
            pCode = ds_fix_work_parts.getCellData(row, "fixWrkUnitNo");
            rtnList = $c.gus.cfCommonPopUp('retrieveFixWrkUnitListInfo', pCode, pName, pClose, null, null, null, null, scwin.argObject.homeClsCd, null, null, null, null, null, "F", "작업단위정보,작업단위코드,작업단위명");
            sameFixWrkUnitNo = 0;
            if (rtnList != null && rtnList[0] != "N/A" && rtnList != undefined) {
                for (let i = 0; i < ds_fix_work_unit.getRowCount(); i++) {
                    if (ds_fix_work_unit.getCellData(i, "fixWrkUnitNo") == rtnList[0]) {
                        sameFixWrkUnitNo = 1;
                        break;
                    }
                }
                if (sameFixWrkUnitNo == 0) {
                    ds_fix_work_parts.setCellData(ds_fix_work_parts.getRowPosition(), "fixWrkUnitNo", "");
                    await $c.win.alert("작업단위에 등록된 작업단위번호만 입력가능합니다.");
                    return false;
                }
            }
            $c.gus.cfSetGridReturnValue(rtnList, ds_fix_work_parts, row, "fixWrkUnitNo", "");
            break;

        case 7:
            pCode = ds_fix_work_parts.getCellData(row, "partCd");
            let addWhere7 = em_fixWrkPlCd.getValue() + "," + ds_fix_work_parts.getCellData(ds_fix_work_parts.getRowPosition(), "inClsCd");
            rtnList = $c.gus.cfCommonPopUp('retrievePartBasicInfo', pCode, pName, pClose, null, null, null, null, addWhere7, null, null, null, null, null, "T", "부품정보,부품코드,부품명");
            if (rtnList != null && rtnList[0] != "N/A" && rtnList != undefined) {
                ds_fix_work_parts.setCellData(row, "partCd", rtnList[0]);
                ds_fix_work_parts.setCellData(row, "partNm", rtnList[1]);
                ds_fix_work_parts.setCellData(row, "partUnitNm", rtnList[3]);
                ds_fix_work_parts.setCellData(row, "clntNo", "");
                ds_fix_work_parts.setCellData(row, "clntNm", "");
                ds_fix_work_parts.setCellData(row, "stockQty", rtnList[7]);
                ds_fix_work_parts.setCellData(row, "outUpr", Math.round(rtnList[6] / rtnList[7]));
                if (ds_fix_work_parts.getCellData(row, "partQty") == "0") {
                    ds_fix_work_parts.setCellData(row, "totAmt", "0");
                    ds_fix_work_parts.setCellData(row, "vatAmt", "0");
                } else {
                    ds_fix_work_parts.setCellData(row, "totAmt", ds_fix_work_parts.getCellData(row, "partQty") * ds_fix_work_parts.getCellData(row, "outUpr"));
                    let taxnCls = ds_fix_work_parts.getCellData(row, "taxnCls");
                    if (taxnCls == "20" || taxnCls == "30") {
                        ds_fix_work_parts.setCellData(row, "vatAmt", 0);
                    } else {
                        ds_fix_work_parts.setCellData(row, "vatAmt", ds_fix_work_parts.getCellData(row, "totAmt") / 10);
                    }
                }
                if (ds_fix_work_parts.getCellData(ds_fix_work_parts.getRowPosition(), "inClsCd") == "3") {
                    scwin.f_openCommPopUpGrid(8, row, 'T');
                }
            } else {
                ds_fix_work_parts.setCellData(row, "inClsCd", "1");
                ds_fix_work_parts.setCellData(row, "partCd", "");
                ds_fix_work_parts.setCellData(row, "partNm", "");
                ds_fix_work_parts.setCellData(row, "partUnitNm", "");
                ds_fix_work_parts.setCellData(row, "clntNo", "");
                ds_fix_work_parts.setCellData(row, "clntNm", "");
                ds_fix_work_parts.setCellData(row, "stockQty", "");
                ds_fix_work_parts.setCellData(row, "outUpr", 0);
                ds_fix_work_parts.setCellData(row, "partQty", "0");
                ds_fix_work_parts.setCellData(row, "totAmt", "0");
                ds_fix_work_parts.setCellData(row, "vatAmt", "0");
            }
            break;

        case 8:
            pCode = em_fixWrkPlCd.getValue();
            pName = ds_fix_work_parts.getCellData(row, "partCd");
            let addWhere8 = ds_fix_work_parts.getCellData(row, "inClsCd");
            rtnList = $c.gus.cfCommonPopUp('retrieveStockCustomer', pCode, pName, pClose, 8, "거래처,금액,수량,거래처코드,,부품코드,작업장,입고구분", "80,50,45,60,0,100,70,60", null, addWhere8, null, null, null, null, null, "T", "부품정보,정비작업장,부품코드");
            if (rtnList != null && rtnList[0] != "N/A" && rtnList != undefined) {
                $c.gus.cfSetGridReturnValue(rtnList, ds_fix_work_parts, ds_fix_work_parts.getRowPosition(), "clntNm", "totAmt");
                ds_fix_work_parts.setCellData(row, "clntNo", rtnList[3]);
                ds_fix_work_parts.setCellData(row, "stockQty", rtnList[2]);
                ds_fix_work_parts.setCellData(row, "taxnCls", rtnList[4]);
                ds_fix_work_parts.setCellData(row, "outUpr", rtnList[1] / rtnList[2]);
                if (ds_fix_work_parts.getCellData(row, "partQty") == "0") {
                    ds_fix_work_parts.setCellData(row, "totAmt", "0");
                    ds_fix_work_parts.setCellData(row, "vatAmt", "0");
                } else {
                    ds_fix_work_parts.setCellData(row, "totAmt", ds_fix_work_parts.getCellData(row, "partQty") * ds_fix_work_parts.getCellData(row, "outUpr"));
                    let taxnCls = ds_fix_work_parts.getCellData(row, "taxnCls");
                    if (taxnCls == "20" || taxnCls == "30") {
                        ds_fix_work_parts.setCellData(row, "vatAmt", 0);
                    } else {
                        ds_fix_work_parts.setCellData(row, "vatAmt", ds_fix_work_parts.getCellData(row, "totAmt") / 10);
                    }
                }
            } else {
                ds_fix_work_parts.setCellData(row, "inClsCd", "1");
            }
            break;
    }
};

scwin.f_AddRow = function(grd) {
    if (scwin.cvUpdate == false && scwin.cvNNew == false) return;

    switch (grd) {
        case 1:
            ds_fix_work_standard.insertRow(ds_fix_work_standard.getRowCount());
            let stdPos = ds_fix_work_standard.getRowPosition();
            ds_fix_work_standard.setCellData(stdPos, "fixWrkPlCd", em_fixWrkPlCd.getValue());
            ds_fix_work_standard.setCellData(stdPos, "fixWrkNo", em_fixWrkNo.getValue());
            ds_fix_work_standard.setCellData(stdPos, "homeClsCd", scwin.argObject.homeClsCd || "");
            break;

        case 2:
            ds_fix_work_unit.insertRow(ds_fix_work_unit.getRowCount());
            let unitPos = ds_fix_work_unit.getRowPosition();
            ds_fix_work_unit.setCellData(unitPos, "fixWrkPlCd", em_fixWrkPlCd.getValue());
            ds_fix_work_unit.setCellData(unitPos, "fixWrkNo", em_fixWrkNo.getValue());
            ds_fix_work_unit.setCellData(unitPos, "homeClsCd", scwin.argObject.homeClsCd || "");
            ds_fix_work_unit.setCellData(unitPos, "dayNgtClsCd", "D");
            ds_fix_work_unit.setCellData(unitPos, "offDayClsCd", "D");
            break;

        case 3:
            ds_fix_driver.insertRow(ds_fix_driver.getRowCount());
            let drvPos = ds_fix_driver.getRowPosition();
            ds_fix_driver.setCellData(drvPos, "fixWrkPlCd", em_fixWrkPlCd.getValue());
            ds_fix_driver.setCellData(drvPos, "fixWrkNo", em_fixWrkNo.getValue());
            ds_fix_driver.setCellData(drvPos, "homeClsCd", scwin.argObject.homeClsCd || "");
            ds_fix_driver.setCellData(drvPos, "wrkStDt", ica_wrkStDt.getValue());
            ds_fix_driver.setCellData(drvPos, "wrkStHh", em_wrkStHh.getValue());
            ds_fix_driver.setCellData(drvPos, "wrkEndDt", ica_wrkEndDt.getValue());
            ds_fix_driver.setCellData(drvPos, "wrkEndHh", em_wrkEndHh.getValue());
            let unitRowPos = ds_fix_work_unit.getRowPosition();
            if (unitRowPos >= 0) {
                ds_fix_driver.setCellData(drvPos, "fixWrkUnitNo", ds_fix_work_unit.getCellData(unitRowPos, "fixWrkUnitNo"));
            }
            ds_fix_driver.setCellData(drvPos, "wrkHhCnt", "0.5");
            scwin.f_calcWrkTime();
            break;

        case 4:
            ds_repair_circula_parts.insertRow(ds_repair_circula_parts.getRowCount());
            let rcpPos = ds_repair_circula_parts.getRowPosition();
            ds_repair_circula_parts.setCellData(rcpPos, "fixWrkPlCd", em_fixWrkPlCd.getValue());
            ds_repair_circula_parts.setCellData(rcpPos, "fixWrkNo", em_fixWrkNo.getValue());
            ds_repair_circula_parts.setCellData(rcpPos, "homeClsCd", scwin.argObject.homeClsCd || "");
            break;

        case 5:
            ds_fix_work_parts.insertRow(ds_fix_work_parts.getRowCount());
            let prtPos = ds_fix_work_parts.getRowPosition();
            ds_fix_work_parts.setCellData(prtPos, "fixWrkPlCd", em_fixWrkPlCd.getValue());
            ds_fix_work_parts.setCellData(prtPos, "fixWrkNo", em_fixWrkNo.getValue());
            ds_fix_work_parts.setCellData(prtPos, "inClsCd", "1");
            ds_fix_work_parts.setCellData(prtPos, "homeClsCd", scwin.argObject.homeClsCd || "");
            let unitRowPos2 = ds_fix_work_unit.getRowPosition();
            if (unitRowPos2 >= 0) {
                ds_fix_work_parts.setCellData(prtPos, "fixWrkUnitNo", ds_fix_work_unit.getCellData(unitRowPos2, "fixWrkUnitNo"));
            }
            ds_fix_work_parts.setCellData(prtPos, "realOutDt", ica_wrkEndDt.getValue());
            break;
    }
};

scwin.f_ApplyFixWorkStandard = async function() {
    if ((scwin.cvNNew == false && scwin.cvUpdate == false) || ds_fix_work_standard.getRowCount() < 1) return;

    for (let row = 0; row < ds_fix_work_standard.getRowCount(); row++) {
        if (ds_fix_work_standard.getCellData(row, "fixWrkStndNo") == "") return;
    }

    if (ds_fix_work_unit.getUpdatedIndex().length > 0 || ds_fix_work_parts.getUpdatedIndex().length > 0) {
        let chk = await $c.gus.cfConfirmMsg(MSG_CM_CRM_005);
        if (!chk) return;
    }

    ds_fix_work_unit.removeAll();
    ds_fix_work_parts.removeAll();
    ds_fix_driver.removeAll();

    for (let row = 0; row < ds_fix_work_standard.getRowCount(); row++) {
        ds_fix_work_standard.setCellData(row, "eqCd", em_eqCd.getValue());
        ds_fix_work_standard.setCellData(row, "homeClsCd", scwin.argObject.homeClsCd || "");
    }

    sbm_applyFixWorkStandard.action = "/ps.eq.fixwrkmgnt.fixwrkmgnt.ApplyFixWorkStandardCMD.do";
    await $c.sbm.execute(sbm_applyFixWorkStandard);

    for (let row = 0; row < ds_fix_work_unit_apply.getRowCount(); row++) {
        ds_fix_work_unit_apply.setCellData(row, "dayNgtClsCd", "D");
        ds_fix_work_unit_apply.setCellData(row, "offDayClsCd", "D");
        ds_fix_work_unit_apply.setCellData(row, "wrkHhCnt", "0");
    }

    // TODO: ImportData equivalent - copy ds_fix_work_unit_apply to ds_fix_work_unit

    if (lux_selfOutordClsCd.getValue() == "IN") {
        for (let row = 0; row < ds_fix_work_unit.getRowCount(); row++) {
            if (ds_fix_work_unit.getRowStatus(row) != "C") continue;
            if (ds_fix_work_unit.getCellData(row, "fixWrkUnitNo") == "") continue;
            scwin.f_AddRow(3);
            ds_fix_driver.setCellData(ds_fix_driver.getRowPosition(), "fixWrkUnitNo", ds_fix_work_unit.getCellData(row, "fixWrkUnitNo"));
        }
    }

    // TODO: ImportData equivalent - copy ds_fix_work_parts_apply to ds_fix_work_parts

    ds_fix_work.set("applyFixWorkStandardYn", "1");
};

scwin.f_applyFixWorkUnit = async function(row, fixWrkUnitNo) {
    sbm_applyFixWorkUnit.action = "/ps.eq.fixwrkmgnt.fixwrkmgnt.ApplyFixWorkUnitCMD.do?fixWorkUnitNumber=" + fixWrkUnitNo + "&homeClsCd=" + (scwin.argObject.homeClsCd || "") + "&eqCd=" + em_eqCd.getValue() + "&fixWrkPlCd=" + em_fixWrkPlCd.getValue();
    await $c.sbm.execute(sbm_applyFixWorkUnit);

    let partRow = ds_fix_work_parts.getRowCount();
    for (let r = 0; r < ds_fix_work_parts_apply.getRowCount(); r++, partRow++) {
        ds_fix_work_parts.insertRow(partRow);
        ds_fix_work_parts.setCellData(partRow, "fixWrkPlCd", em_fixWrkPlCd.getValue());
        ds_fix_work_parts.setCellData(partRow, "fixWrkNo", em_fixWrkNo.getValue());
        ds_fix_work_parts.setCellData(partRow, "fixWrkUnitNo", ds_fix_work_parts_apply.getCellData(r, "fixWrkUnitNo"));
        ds_fix_work_parts.setCellData(partRow, "partCd", ds_fix_work_parts_apply.getCellData(r, "partCd"));
        ds_fix_work_parts.setCellData(partRow, "partNm", ds_fix_work_parts_apply.getCellData(r, "partNm"));
        ds_fix_work_parts.setCellData(partRow, "partUnitNm", ds_fix_work_parts_apply.getCellData(r, "partUnitNm"));
        ds_fix_work_parts.setCellData(partRow, "inClsCd", "1");
        ds_fix_work_parts.setCellData(partRow, "outUpr", ds_fix_work_parts_apply.getCellData(r, "outUpr"));
        ds_fix_work_parts.setCellData(partRow, "partQty", ds_fix_work_parts_apply.getCellData(r, "partQty"));
        ds_fix_work_parts.setCellData(partRow, "stockQty", ds_fix_work_parts_apply.getCellData(r, "stockQty"));
    }
};

