scwin.f_ctrlFixKndCd = function() {
    chk_ioNesYn.setValue("1");
    $c.gus.cfDisableObjects([chk_ioNesYn]);

    $c.gus.cfDisableObjects([txt_accdRecptNo, img_accdRecptNo]);

    let fixKndCdVal = lux_fixKndCd.getValue();

    if (fixKndCdVal == "02") {
        $c.gus.cfEnableObjects([txt_accdRecptNo, img_accdRecptNo]);
        $c.gus.cfDisableObjects([em_circulPartCd, txt_circulPartNm]);
    } else if (fixKndCdVal == "04") {
        $c.gus.cfEnableObjects([em_circulPartCd, txt_circulPartNm]);
        em_circulPartCd.setFocus();
        chk_ioNesYn.setValue("0");
        $c.gus.cfDisableObjects([chk_ioNesYn]);
        scwin.f_ioNesYn();
        txt_damageWrongTyp.setValue("");
    } else if (fixKndCdVal == "13") {
        lux_passYn.setValue("1");
        lux_inspKndCd.setValue("2");
        $c.gus.cfEnableObjects([ica_nextExpireDt]);
        txt_damageWrongTyp.setValue("");
    } else if (fixKndCdVal == "14") {
        lux_passYn.setValue("1");
        lux_inspKndCd.setValue("1");
        ica_nextExpireDt.setMandatory(true);
        $c.gus.cfEnableObjects([ica_nextExpireDt]);
        txt_damageWrongTyp.setValue("");
    } else if (fixKndCdVal == "15") {
        lux_passYn.setValue("1");
        lux_inspKndCd.setValue("3");
        ica_nextExpireDt.setMandatory(true);
        $c.gus.cfEnableObjects([ica_nextExpireDt]);
        txt_damageWrongTyp.setValue("");
    } else {
        txt_damageWrongTyp.setValue("");
        $c.gus.cfDisableObjects([em_circulPartCd, txt_circulPartNm]);
    }

    scwin.f_initFixResult(fixKndCdVal);
    scwin.f_ioNesYn();
    $c.gus.cfRefreshMandSign();
};

