scwin.em_inHh_onblur = async function(e) {
    let val = em_inHh.getValue().trim();
    if (val != "" && (val.length < 4 || val.substring(0, 2) > "24" || val.substring(2, 4) > "59" || val > "2459")) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_055, ["입고시각"]);
        em_inHh.setValue("");
        em_inHh.setFocus();
    }
    if (em_wrkStHh.getValue().trim() == "") {
        em_wrkStHh.setValue(em_inHh.getValue());
    }
};

