scwin.ica_wrkStDt_onblur = function(e) {
    let wrkStDtVal = ica_wrkStDt.getValue().trim();
    let wrkEndDtVal = ica_wrkEndDt.getValue().trim();
    if (wrkEndDtVal != "" && wrkStDtVal != "") {
        em_needDt.setValue($c.date.diffDate(wrkStDtVal, wrkEndDtVal));
    }
    if (em_wrkIntendDt.getValue().trim() == "") {
        em_wrkIntendDt.setValue(wrkStDtVal);
    }
    if (ica_inDt.getValue().trim() == "") {
        ica_inDt.setValue(wrkStDtVal);
    }
};

