scwin.gr_fix_work_standard_ontextimageclick = function(rowIndex, columnIndex, columnId) {
    scwin.f_openCommPopUpGrid(1, rowIndex, 'F');
};

scwin.gr_fix_work_unit_ontextimageclick = function(rowIndex, columnIndex, columnId) {
    let data = ds_fix_work_unit.getCellData(rowIndex, "fixWrkUnitNo");
    if (data == "") {
        scwin.f_openCommPopUpGrid(2, rowIndex, 'F');
        if (lux_selfOutordClsCd.getValue() == "IN") {
            if (ds_fix_work_unit.getRowStatus(rowIndex) != "C") return;
            if (ds_fix_work_unit.getCellData(rowIndex, "fixWrkUnitNo") == "") return;
            scwin.f_AddRow(3);
            ds_fix_driver.setCellData(ds_fix_driver.getRowPosition(), "fixWrkUnitNo", ds_fix_work_unit.getCellData(rowIndex, "fixWrkUnitNo"));
        }
    }
};

scwin.gr_fix_driver_ontextimageclick = function(rowIndex, columnIndex, columnId) {
    if (rowIndex >= 0 && ds_fix_driver.getRowCount() > rowIndex) {
        switch (columnId) {
            case "fixWrkUnitNo":
                scwin.f_openCommPopUpGrid(3, rowIndex, 'F');
                break;
            case "fixEmpNm":
                scwin.f_openCommPopUpGrid(4, rowIndex, 'F');
                break;
            case "wrkStDt":
                $c.gus.cfOpenCalendar(gr_fix_driver, rowIndex, columnId);
                break;
            case "wrkEndDt":
                $c.gus.cfOpenCalendar(gr_fix_driver, rowIndex, columnId);
                break;
        }
    }
};

