scwin.ds_fix_work_parts_oncelldatachange = async function(info) {
    let row = info.row;
    let colid = info.colId;

    if (colid == "capExpdYn") {
        if (ds_fix_work_parts.getCellData(row, "partOutNo") != "") {
            if (scwin.onRollBack == false) {
                scwin.onRollBack = true;
                if (ds_fix_work_parts.getCellData(row, colid) == "0") {
                    ds_fix_work_parts.setCellData(row, colid, "1");
                } else {
                    ds_fix_work_parts.setCellData(row, colid, "0");
                }
                await $c.win.alert("출고가 완료된 부품은 수정할 수 없습니다.");
            } else {
                scwin.onRollBack = false;
            }
        }
    }

    if (colid == "partQty") {
        if (ds_fix_work_parts.getCellData(row, "partQty") == "0") {
            ds_fix_work_parts.setCellData(row, "totAmt", "0");
            ds_fix_work_parts.setCellData(row, "vatAmt", "0");
        } else {
            ds_fix_work_parts.setCellData(row, "totAmt", ds_fix_work_parts.getCellData(row, "partQty") * ds_fix_work_parts.getCellData(row, "outUpr"));
            let taxnCls = ds_fix_work_parts.getCellData(row, "taxnCls");
            if (taxnCls == "20" || taxnCls == "30") {
                ds_fix_work_parts.setCellData(row, "vatAmt", 0);
            } else {
                ds_fix_work_parts.setCellData(row, "vatAmt", ds_fix_work_parts.getCellData(row, "totAmt") / 10);
            }
        }
        scwin.f_setAdjustment();
    }

    if (colid == "inClsCd") {
        scwin.f_RetrieveStockCustomer(row);
    }
};

scwin.ds_fix_driver_oncelldatachange = function(info) {
    let row = info.row;
    let colid = info.colId;
    if (row < 0) return;
    switch (colid) {
        case "wrkHhCnt":
            scwin.f_calcWrkTime();
            break;
    }
};

scwin.ds_fix_work_unit_oncelldatachange = function(info) {
    let colid = info.colId;
    if (colid == "qty" || colid == "upr" || colid == "bilgWages" || colid == "vatAmt") {
        scwin.f_setAdjustment();
    }
};

